const getAdminContentData = `-- name: GetAdminContentData :one
SELECT admin_content_data_id, parent_id, first_child_id, next_sibling_id, prev_sibling_id, root_id, admin_route_id, admin_datatype_id, author_id, status, date_created, date_modified, published_at, published_by, publish_at, revision FROM admin_content_data
WHERE admin_content_data_id = $1 LIMIT 1
`

type GetAdminContentDataParams struct {
	AdminContentDataID types.AdminContentID `json:"admin_content_data_id"`
}

func (q *Queries) GetAdminContentData(ctx context.Context, arg GetAdminContentDataParams) (AdminContentData, error) {
	row := q.db.QueryRowContext(ctx, getAdminContentData, arg.AdminContentDataID)
	var i AdminContentData
	err := row.Scan(
		&i.AdminContentDataID,
		&i.ParentID,
		&i.FirstChildID,
		&i.NextSiblingID,
		&i.PrevSiblingID,
		&i.RootID,
		&i.AdminRouteID,
		&i.AdminDatatypeID,
		&i.AuthorID,
		&i.Status,
		&i.DateCreated,
		&i.DateModified,
		&i.PublishedAt,
		&i.PublishedBy,
		&i.PublishAt,
		&i.Revision,
	)
	return i, err
}

const getAdminContentDataDescendants = `-- name: GetAdminContentDataDescendants :many
WITH RECURSIVE tree AS (
    SELECT cd1.admin_content_data_id AS cid FROM admin_content_data cd1 WHERE cd1.admin_content_data_id = $1
    UNION ALL
    SELECT cd2.admin_content_data_id FROM admin_content_data cd2
    INNER JOIN tree t ON cd2.parent_id = t.cid
)
SELECT cd.admin_content_data_id, cd.parent_id, cd.first_child_id, cd.next_sibling_id, cd.prev_sibling_id, cd.root_id, cd.admin_route_id, cd.admin_datatype_id, cd.author_id, cd.status, cd.date_created, cd.date_modified, cd.published_at, cd.published_by, cd.publish_at, cd.revision FROM admin_content_data cd
INNER JOIN tree t ON cd.admin_content_data_id = t.cid
`

type GetAdminContentDataDescendantsParams struct {
	AdminContentDataID types.AdminContentID `json:"admin_content_data_id"`
}

func (q *Queries) GetAdminContentDataDescendants(ctx context.Context, arg GetAdminContentDataDescendantsParams) ([]AdminContentData, error) {
	rows, err := q.db.QueryContext(ctx, getAdminContentDataDescendants, arg.AdminContentDataID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []AdminContentData{}
	for rows.Next() {
		var i AdminContentData
		if err := rows.Scan(
			&i.AdminContentDataID,
			&i.ParentID,
			&i.FirstChildID,
			&i.NextSiblingID,
			&i.PrevSiblingID,
			&i.RootID,
			&i.AdminRouteID,
			&i.AdminDatatypeID,
			&i.AuthorID,
			&i.Status,
			&i.DateCreated,
			&i.DateModified,
			&i.PublishedAt,
			&i.PublishedBy,
			&i.PublishAt,
			&i.Revision,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

